const express = require('express');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(helmet());
app.use(express.json({ limit: '10kb' }));

const SECRET_KEY = process.env.GAME_SECRET_KEY || crypto.randomBytes(32).toString('hex');
const HMAC_ALGORITHM = 'sha256';

const gameState = new Map();
const rewardsClaimed = new Map();

const LEVEL_CONFIG = {
  1: { minTime: 10, maxTime: 300, minScore: 0, maxScore: 1000, reward: 10 },
  2: { minTime: 15, maxTime: 400, minScore: 0, maxScore: 1500, reward: 15 },
  3: { minTime: 20, maxTime: 500, minScore: 0, maxScore: 2000, reward: 20 },
  4: { minTime: 25, maxTime: 600, minScore: 0, maxScore: 2500, reward: 25 },
  5: { minTime: 30, maxTime: 700, minScore: 0, maxScore: 3000, reward: 30 }
};

const MAX_LEVELS = 5;
const SESSION_TIMEOUT = 3600000;

const completionLimiter = rateLimit({
  windowMs: 60000,
  max: 10,
  message: { error: 'Too many requests' },
  standardHeaders: true,
  legacyHeaders: false
});

const rewardLimiter = rateLimit({
  windowMs: 60000,
  max: 20,
  message: { error: 'Too many requests' },
  standardHeaders: true,
  legacyHeaders: false
});

function generateHMAC(data, secret) {
  return crypto.createHmac(HMAC_ALGORITHM, secret).update(JSON.stringify(data)).digest('hex');
}

function verifyHMAC(data, signature, secret) {
  const expected = generateHMAC(data, secret);
  return crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected));
}

function generateSessionToken(userId) {
  const payload = {
    userId,
    timestamp: Date.now(),
    nonce: crypto.randomBytes(16).toString('hex')
  };
  const signature = generateHMAC(payload, SECRET_KEY);
  return Buffer.from(JSON.stringify({ ...payload, signature })).toString('base64');
}

function verifySessionToken(token) {
  try {
    const decoded = JSON.parse(Buffer.from(token, 'base64').toString('utf8'));
    const { userId, timestamp, nonce, signature } = decoded;
    
    if (!userId || !timestamp || !nonce || !signature) {
      return null;
    }
    
    if (Date.now() - timestamp > SESSION_TIMEOUT) {
      return null;
    }
    
    const payload = { userId, timestamp, nonce };
    if (!verifyHMAC(payload, signature, SECRET_KEY)) {
      return null;
    }
    
    return { userId, timestamp };
  } catch (e) {
    return null;
  }
}

function authenticateRequest(req, res, next) {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  
  const token = authHeader.substring(7);
  const session = verifySessionToken(token);
  
  if (!session) {
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
  
  req.userId = session.userId;
  next();
}

function validateLevelData(level, score, time) {
  if (!Number.isInteger(level) || level < 1 || level > MAX_LEVELS) {
    return { valid: false, error: 'Invalid level' };
  }
  
  if (!Number.isInteger(score) || score < 0) {
    return { valid: false, error: 'Invalid score' };
  }
  
  if (!Number.isInteger(time) || time < 0) {
    return { valid: false, error: 'Invalid time' };
  }
  
  const config = LEVEL_CONFIG[level];
  if (!config) {
    return { valid: false, error: 'Level configuration not found' };
  }
  
  if (score < config.minScore || score > config.maxScore) {
    return { valid: false, error: 'Score out of valid range' };
  }
  
  if (time < config.minTime || time > config.maxTime) {
    return { valid: false, error: 'Time out of valid range' };
  }
  
  return { valid: true, config };
}

function detectAnomalies(userId, level, score, time) {
  const userKey = `${userId}`;
  const state = gameState.get(userKey) || { completions: [], lastCompletion: 0 };
  
  const now = Date.now();
  const timeSinceLastCompletion = now - state.lastCompletion;
  
  if (timeSinceLastCompletion < 5000) {
    return { suspicious: true, reason: 'Completion too fast' };
  }
  
  const recentCompletions = state.completions.filter(c => now - c.timestamp < 300000);
  if (recentCompletions.length >= 15) {
    return { suspicious: true, reason: 'Too many completions in short time' };
  }
  
  const config = LEVEL_CONFIG[level];
  const scoreTimeRatio = score / time;
  const maxRatio = config.maxScore / config.minTime;
  
  if (scoreTimeRatio > maxRatio * 1.5) {
    return { suspicious: true, reason: 'Unrealistic score-time ratio' };
  }
  
  const sameScoreCount = recentCompletions.filter(c => c.level === level && c.score === score).length;
  if (sameScoreCount >= 3) {
    return { suspicious: true, reason: 'Identical scores detected' };
  }
  
  return { suspicious: false };
}

function updateGameState(userId, level, score, time) {
  const userKey = `${userId}`;
  const state = gameState.get(userKey) || { completions: [], lastCompletion: 0 };
  
  state.completions.push({
    level,
    score,
    time,
    timestamp: Date.now()
  });
  
  if (state.completions.length > 100) {
    state.completions = state.completions.slice(-100);
  }
  
  state.lastCompletion = Date.now();
  gameState.set(userKey, state);
}

app.post('/api/auth/login', (req, res) => {
  const { userId } = req.body;
  
  if (!userId || typeof userId !== 'string' || userId.length < 3 || userId.length > 50) {
    return res.status(400).json({ error: 'Invalid userId' });
  }
  
  if (!/^[a-zA-Z0-9_-]+$/.test(userId)) {
    return res.status(400).json({ error: 'Invalid userId format' });
  }
  
  const token = generateSessionToken(userId);
  
  res.json({ token });
});

app.post('/api/levels/complete', authenticateRequest, completionLimiter, (req, res) => {
  const { level, score, time, signature } = req.body;
  
  if (!signature || typeof signature !== 'string') {
    return res.status(400).json({ error: 'Missing signature' });
  }
  
  const payload = { level, score, time, userId: req.userId };
  if (!verifyHMAC(payload, signature, SECRET_KEY)) {
    return res.status(403).json({ error: 'Invalid signature' });
  }
  
  const validation = validateLevelData(level, score, time);
  if (!validation.valid) {
    return res.status(400).json({ error: validation.error });
  }
  
  const anomalyCheck = detectAnomalies(req.userId, level, score, time);
  if (anomalyCheck.suspicious) {
    return res.status(403).json({ 
      error: 'Suspicious activity detected',
      details: anomalyCheck.reason 
    });
  }
  
  updateGameState(req.userId, level, score, time);
  
  const completionId = crypto.randomBytes(16).toString('hex');
  const completionData = {
    completionId,
    userId: req.userId,
    level,
    score,
    time,
    timestamp: Date.now()
  };
  
  const completionSignature = generateHMAC(completionData, SECRET_KEY);
  
  res.json({
    success: true,
    completionId,
    signature: completionSignature,
    reward: validation.config.reward
  });
});

app.post('/api/rewards/claim', authenticateRequest, rewardLimiter, (req, res) => {
  const { completionId, signature } = req.body;
  
  if (!completionId || typeof completionId !== 'string') {
    return res.status(400).json({ error: 'Invalid completionId' });
  }
  
  if (!signature || typeof signature !== 'string') {
    return res.status(400).json({ error: 'Missing signature' });
  }
  
  const claimKey = `${req.userId}:${completionId}`;
  if (rewardsClaimed.has(claimKey)) {
    return res.status(400).json({ error: 'Reward already claimed' });
  }
  
  const userState = gameState.get(req.userId);
  if (!userState) {
    return res.status(404).json({ error: 'No game state found' });
  }
  
  const completion = userState.completions.find(c => {
    const tempData = {
      completionId,
      userId: req.userId,
      level: c.level,
      score: c.score,
      time: c.time,
      timestamp: c.timestamp
    };
    const expectedSig = generateHMAC(tempData, SECRET_KEY);
    return expectedSig === signature;
  });
  
  if (!completion) {
    return res.status(404).json({ error: 'Invalid completion or signature' });
  }
  
  const config = LEVEL_CONFIG[completion.level];
  if (!config) {
    return res.status(500).json({ error: 'Configuration error' });
  }
  
  rewardsClaimed.set(claimKey, {
    timestamp: Date.now(),
    reward: config.reward
  });
  
  res.json({
    success: true,
    reward: config.reward,
    currency: 'coins'
  });
});

app.get('/api/player/stats', authenticateRequest, (req, res) => {
  const userState = gameState.get(req.userId);
  
  if (!userState) {
    return res.json({
      totalCompletions: 0,
      levels: {}
    });
  }
  
  const levelStats = {};
  userState.completions.forEach(c => {
    if (!levelStats[c.level]) {
      levelStats[c.level] = {
        attempts: 0,
        bestScore: 0,
        bestTime: Infinity
      };
    }
    levelStats[c.level].attempts++;
    levelStats[c.level].bestScore = Math.max(levelStats[c.level].bestScore, c.score);
    levelStats[c.level].bestTime = Math.min(levelStats[c.level].bestTime, c.time);
  });
  
  res.json({
    totalCompletions: userState.completions.length,
    levels: levelStats
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Game API server running on port ${PORT}`);
});

module.exports = app;